INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Customer Health Scorecards$q$, $q$Configurable scoring models that combine product usage, support activity, survey results, and relationship data into a single health rating per account.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Playbooks & Cockpit$q$, $q$Automated task and workflow triggers that fire when an account's health, usage, or lifecycle stage changes, keeping success managers focused on the right accounts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Timeline$q$, $q$A running activity log of calls, emails, meeting notes, and touchpoints for each account, giving teams continuity when ownership changes.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Journey Orchestrator$q$, $q$Automated, segmented email and in-app messaging campaigns used to guide customers through onboarding, adoption, and renewal milestones.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Renewal Center$q$, $q$Centralized tracking and forecasting of upcoming renewals, including risk flags and revenue at stake across the customer portfolio.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Gainsight PX$q$, $q$In-product analytics and engagement tools, including usage tracking, walkthroughs, and feature adoption reporting for product and CS teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Customer Communities$q$, $q$A branded online community space where customers can ask questions, share best practices, and access self-service knowledge content.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Reports & Dashboards$q$, $q$Configurable reporting views for individual account health, team-level performance, and portfolio-wide renewal and churn trends.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Surveys$q$, $q$Built-in tools for collecting NPS, CSAT, and other customer feedback that feed directly into health scores and workflows.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$CRM & Tool Integrations$q$, $q$Native integrations with Salesforce, HubSpot, Slack, Zendesk, Marketo, and other systems to keep customer data synchronized across the stack.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Deep, configurable customer health scoring that combines multiple data sources into one view$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Strong workflow automation through playbooks reduces manual, repetitive CS tasks$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Broad product suite covering onboarding, product analytics, communities, and renewals in one ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Mature integrations with major CRMs and support tools used by enterprise sales and success teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Well suited to managing large, segmented customer portfolios with different engagement tiers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Pricing is entirely custom and quote-based, making upfront cost comparison difficult$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Implementation and configuration require meaningful time investment and clean underlying data$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Can be overkill for small teams or companies without a dedicated customer success function$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Learning curve for administrators setting up scorecards, playbooks, and reporting logic$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Best value depends on already having a CRM and usage data pipeline in place to integrate$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$What does Gainsight do?$q$, $q$Gainsight is a customer success management platform that helps B2B SaaS companies track customer health, automate outreach through playbooks, and manage the full customer lifecycle from onboarding through renewal and expansion.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$How much does Gainsight cost?$q$, $q$Gainsight does not publish standard pricing. Costs are quote-based and depend on factors like number of users, products selected (such as core CS, PX, or Communities), and contract terms, so prospective customers need to contact sales for a quote.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Is there a free trial or free plan for Gainsight?$q$, $q$Gainsight is positioned as an enterprise platform sold through direct sales, and it does not advertise a public free-trial or free-tier signup; interested teams typically request a demo and custom quote.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$What integrations does Gainsight support?$q$, $q$Gainsight integrates with common business systems including Salesforce, HubSpot, Slack, Zendesk, and Marketo, among others, allowing customer, support, and marketing data to sync with health scores and workflows.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Who typically uses Gainsight?$q$, $q$Gainsight is primarily used by customer success, account management, and renewals teams at B2B SaaS and subscription companies, particularly mid-market and enterprise organizations managing many recurring-revenue accounts.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Customer Onboarding Automation$q$, $q$Automate structured onboarding playbooks and task sequences so new customers are guided consistently toward their first value milestone.$q$, $q$Customer success managers and onboarding teams at SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Churn Risk Detection$q$, $q$Use composite health scores built from usage, support, and survey data to flag at-risk accounts before they churn and trigger intervention playbooks.$q$, $q$Customer success operations and account managers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Renewal and Expansion Forecasting$q$, $q$Track upcoming renewal dates, forecast renewal likelihood, and identify expansion or upsell opportunities across the customer portfolio.$q$, $q$Revenue leaders and renewals/account management teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Product Adoption Tracking$q$, $q$Combine in-app usage analytics from Gainsight PX with account health data to see which features drive retention and where adoption is lagging.$q$, $q$Product managers and customer success teams collaborating on adoption$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Essentials$q$, $q$Custom / Contact sales$q$, $q$Annual contract (custom quote)$q$, $q$["Core customer health scoring","Basic playbooks and task automation","Standard reporting and dashboards","Core CRM integration"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Standard$q$, $q$Custom / Contact sales$q$, $q$Annual contract (custom quote)$q$, $q$["Advanced health scorecards and segmentation","Journey Orchestrator campaigns","Renewal Center tracking and forecasting","Expanded integrations and reporting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$Premier / Enterprise$q$, $q$Custom / Contact sales$q$, $q$Annual contract (custom quote)$q$, $q$["Full product suite including Gainsight PX and Communities","Advanced automation and workflow customization","Dedicated implementation and success support","Enterprise-grade security and administration controls"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Gainsight is a customer success management (CSM) platform built to help subscription and B2B SaaS businesses retain and grow their customer base. Rather than treating customer success as a reactive support function, Gainsight positions it as a data-driven discipline: tracking account health, automating outreach at key lifecycle moments, and giving success teams a single system of record for every customer relationship.$q$, $q$The platform centers on a few core ideas. Customer health scores pull together usage data, support tickets, survey responses, and other signals into a composite view of how likely an account is to renew or churn. Playbooks and automated workflows (often run through a feature called Cockpit) trigger tasks and outreach when specific risk or opportunity signals appear. A Timeline feature logs every touchpoint — calls, emails, meeting notes — so nothing about the account history is lost when a customer success manager changes.$q$, $q$Beyond the core CS product, Gainsight has expanded into a broader suite: Gainsight PX for in-app product analytics and user engagement, a Customer Communities product, Journey Orchestrator for automated lifecycle emails, and a Renewal Center for tracking and forecasting renewals. Together these products aim to cover the full customer lifecycle from onboarding through renewal and expansion, primarily for companies that sell recurring subscriptions and run a dedicated customer success or account management function.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$who-gainsight-is-for$q$, $q$Who Gainsight Is For$q$, 2, ARRAY[$q$Gainsight is built for B2B SaaS and subscription businesses that already have (or are actively building) a customer success or account management team. It's most useful to organizations with meaningful recurring revenue at stake, where losing or shrinking an account has a measurable financial impact and where proactively managing renewals justifies dedicated software and headcount.$q$, $q$It fits companies with enough customer and usage data to make health scoring meaningful — typically those integrated with a CRM such as Salesforce or HubSpot, a product analytics pipeline, and support tools like Zendesk. Mid-market and enterprise SaaS vendors with tiered account segmentation (say, high-touch enterprise accounts alongside a larger pool of lower-touch customers) tend to get the most value, since Gainsight lets teams apply different playbooks and cadences to each segment.$q$, $q$It also suits revenue and customer success leaders who need visibility across the organization: VPs of Customer Success who want portfolio-level health dashboards, renewal forecasts, and reporting to share with executives or the board, rather than success managers relying on personal spreadsheets and instincts.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Very early-stage startups or solo founders with a handful of customers generally don't need Gainsight. Without a dedicated CS team or enough accounts to segment and automate, the platform's health scoring and playbook automation add overhead rather than value, and the effort of configuring integrations, data models, and scorecards outweighs the benefit at that scale.$q$, $q$Companies selling to consumers (B2C) or running high-volume, low-touch transactional businesses without recurring account relationships are also a poor fit — Gainsight's data model and workflows are built around ongoing B2B accounts with renewal cycles, not one-time purchases or mass-market consumer usage.$q$, $q$Teams without an existing CRM, clean customer data, or the internal bandwidth to maintain integrations and scoring rules may struggle to get value quickly. Because pricing is quote-based and typically structured around annual contracts, budget-constrained teams that want simple, self-serve, pay-as-you-go software may prefer a lighter-weight CS tool instead.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, Gainsight combines customer health scoring, workflow automation, and reporting into one system. Health scorecards let teams define custom rules that weigh usage data, support history, survey feedback, and relationship signals into a single health rating per account, which can then drive alerts and prioritization across the success team.$q$, $q$Playbooks and Cockpit automate the operational side of customer success: assigning tasks, triggering outreach sequences, and tracking calls-to-action when an account's health changes or a renewal date approaches. Journey Orchestrator extends this to lifecycle email and in-app campaigns, while the Renewal Center centralizes renewal forecasting and risk tracking for revenue leaders.$q$, $q$Gainsight PX adds product-usage analytics and in-app engagement tools (walkthroughs, guides, feature announcements) so product and CS teams can see adoption patterns directly, and Customer Communities provides a branded space for customers to ask questions and share knowledge. Reporting and dashboards tie these signals together, and native integrations with Salesforce, HubSpot, Slack, Zendesk, and other systems keep customer data synchronized across the tech stack.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', $q$the-gainsight-experience$q$, $q$The Gainsight Experience$q$, 2, ARRAY[$q$Gainsight is a web-based platform administered largely through a configuration layer that CS operations teams build out: defining health score formulas, playbook triggers, and reporting views before individual customer success managers start working day to day inside Timeline, Cockpit, and account dashboards.$q$, $q$Because of that configuration depth, new teams typically go through a structured onboarding and implementation process, often working with Gainsight's own services team or a partner to map their customer data and lifecycle stages into the platform. Once set up, day-to-day use centers on account workspaces that surface health trends, open tasks, and upcoming renewals in one place.$q$, $q$The experience is oriented toward operational rigor rather than simplicity for its own sake — it rewards teams willing to invest in clean data and defined processes with a consolidated, automatable view of the customer base, but it is a substantially heavier tool than a lightweight helpdesk or spreadsheet-based tracking approach.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('ca7516a2-730d-48ae-b2cd-54a3da886bac', 'ee5576d4-5994-49f9-84c2-c9a84cc884f6') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Email marketing editor$q$, $q$A drag-and-drop email builder with a large template library, mobile preview, and dynamic content blocks for building newsletters and campaigns without code.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Marketing automation$q$, $q$A visual workflow builder that triggers multi-step sequences based on subscriber behavior such as opens, clicks, purchases, tag changes, and custom events.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Landing pages$q$, $q$A landing page builder with a large template selection, included on paid plans, for building lead-generation and sales pages without a separate tool.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Conversion funnels$q$, $q$A funnel tool (formerly Autofunnel) that chains a landing page, email sequence, sales page, and checkout into a single guided flow.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Webinars$q$, $q$A built-in webinar platform supporting screen sharing, polls, chat, and recording, with attendee capacity that scales by plan.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$AI content tools$q$, $q$AI-assisted tools for drafting emails, suggesting subject lines, generating a campaign from a stated goal, and building a basic website from a short description.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$E-commerce integrations$q$, $q$Connections to platforms such as Shopify and WooCommerce for abandoned cart emails, product recommendations, and purchase-based automation.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Multichannel marketing$q$, $q$SMS messages, web push notifications, popups, and live chat alongside email, for reaching contacts through more than one channel from a single account.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Website builder$q$, $q$An AI-assisted site builder for creating a simple website or one-page site alongside email and landing page campaigns.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Analytics and reporting$q$, $q$Reporting on email opens, clicks, automation performance, and funnel conversions to track campaign results over time.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Generous free plan that includes email marketing, automation basics, and one landing page for small lists$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Broad feature set (email, automation, landing pages, webinars, funnels, e-commerce) available under one subscription$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$AI tools for drafting emails, subject lines, and full campaigns speed up routine content creation$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Built-in webinar hosting removes the need for a separate webinar tool for many users$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Long operating history and a large template library across email and landing pages$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Pricing scales with contact list size, so costs can rise noticeably as a list grows$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$The automation workflow builder has real depth, which means a steeper learning curve than simpler autoresponder tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Some advanced automation, segmentation, and e-commerce capabilities are limited to higher-priced tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Landing page and funnel customization is less deep than dedicated conversion-rate-optimization or landing page specialist tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Webinar attendee capacity and some support channels depend on which plan you're subscribed to$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Does GetResponse have a free plan?$q$, $q$Yes. GetResponse offers a free plan for a limited number of contacts that includes basic email marketing, one landing page, and simple automation, with no credit card required to sign up.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$What is GetResponse's Conversion Funnel feature?$q$, $q$Conversion Funnel (previously called Autofunnel) is a tool for assembling a landing page, follow-up email sequence, sales page, and checkout into one connected funnel, included with an email marketing subscription rather than sold as a separate product.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Does GetResponse include webinar hosting?$q$, $q$Yes. GetResponse has a built-in webinar tool with screen sharing, polls, chat, and recording, with attendee limits that vary depending on the plan.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Can I import an existing contact list or migrate from another email tool?$q$, $q$Yes. GetResponse supports importing contact lists from spreadsheets or other email service providers, and its help center provides migration guidance for moving existing lists and campaigns over.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Does GetResponse have AI features?$q$, $q$Yes. GetResponse includes AI tools for drafting email copy, suggesting subject lines, generating a campaign from a description of your goal, and building a basic website automatically.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Newsletter and list building for small businesses$q$, $q$Small businesses use GetResponse's forms, landing pages, and email editor to grow a list and send regular newsletters or promotions.$q$, $q$Small business owners and solo marketers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Abandoned cart and post-purchase automation$q$, $q$Online stores connect their e-commerce platform to trigger automated emails for abandoned carts, order confirmations, and product follow-ups.$q$, $q$E-commerce sellers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Content monetization for creators$q$, $q$Newsletter writers and course creators use paid newsletter and course-hosting features alongside email automation to generate recurring revenue from an audience.$q$, $q$Independent creators, coaches, and newsletter publishers$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Webinar-driven lead generation$q$, $q$Consultants and B2B marketers run webinars through the built-in platform and follow up with automated email sequences to convert attendees into customers.$q$, $q$Consultants, agencies, and B2B marketing teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Free$q$, $q$$0/month$q$, $q$monthly$q$, $q$["Up to 500 contacts","Email marketing tools","One landing page","Basic automation","Website builder access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Starter$q$, $q$From $19/month (1,000 contacts)$q$, $q$monthly or annual (annual billing offers a discount)$q$, $q$["Unlimited emails","Autoresponders","Unlimited landing pages","Basic e-commerce integrations","24/7 chat support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Marketer$q$, $q$From $59/month (1,000 contacts)$q$, $q$monthly or annual (annual billing offers a discount)$q$, $q$["Everything in Starter","Advanced marketing automation","Abandoned cart emails","Contact scoring and tagging","Webinars"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$Creator$q$, $q$From $69/month (1,000 contacts)$q$, $q$monthly or annual (annual billing offers a discount)$q$, $q$["Everything in Marketer","Paid newsletter tools","Course hosting","Content monetization features","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GetResponse started in 1998 as a simple email autoresponder built by its founder, Simon Grabowski, and has grown into a broad marketing platform used by small businesses, solo creators, and marketing teams around the world. Rather than positioning itself as a single-purpose email sender, the company has spent two decades layering on adjacent tools: marketing automation, landing pages, conversion funnels, webinars, e-commerce integrations, a website builder, and more recently a set of AI-assisted content and campaign tools.$q$, $q$The core pitch is consolidation. Instead of paying separately for an email service provider, a landing page builder, a webinar host, and an automation engine, GetResponse bundles most of that into tiered subscriptions priced primarily by contact list size. A free plan covers a small list and the basics, while paid tiers unlock higher contact limits, more automation logic, e-commerce features, and content monetization tools like paid newsletters and course hosting.$q$, $q$It remains privately held and self-funded rather than venture-backed, which shows up in a product that evolves steadily rather than chasing every trend. The platform is best understood as a generalist marketing suite: broad in scope, web-based, and built for teams that would rather manage one subscription and one dashboard than stitch together several specialized tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$who-its-for$q$, $q$Who GetResponse Is For$q$, 2, ARRAY[$q$Small business owners and solo marketers who need to build an email list, send newsletters, and set up a handful of automated sequences (welcome emails, abandoned cart reminders, re-engagement flows) are the most natural fit. The free plan and entry-level paid tiers give this group a usable feature set without a large upfront commitment, and the drag-and-drop email editor keeps day-to-day work approachable for non-technical users.$q$, $q$Content creators, coaches, and newsletter publishers who want to monetize an audience are a second core audience. Plans built around content creation combine paid newsletters, simple course hosting, and automation in one place, which appeals to people who would otherwise need a separate course platform or membership tool alongside their email software.$q$, $q$E-commerce sellers and webinar-driven businesses also fit well. Store owners can connect platforms like Shopify or WooCommerce for abandoned cart flows and product-based automation, while consultants, agencies, and B2B marketers running webinars for lead generation get a built-in webinar tool instead of paying for a separate service like Zoom Webinars or Livestorm. Agencies managing several client accounts can also use the platform's broader feature set to avoid juggling different vendors for each client's email, landing page, and automation needs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$who-should-avoid$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Teams that need a best-in-class tool for one specific job rather than a generalist suite may be better served elsewhere. A conversion-rate-optimization team that lives inside a landing page builder with advanced A/B testing and deep heatmap analytics, for example, will likely find dedicated tools more capable in that one area than GetResponse's built-in landing page and funnel features.$q$, $q$Organizations with very large or fast-growing contact lists that are sensitive to cost should model pricing carefully before committing. Because plans are priced by contact count, the monthly bill climbs as a list grows, and at high volumes it is worth comparing against alternatives with different pricing structures or against GetResponse's own contact-sales enterprise tier.$q$, $q$Developers or product teams that only need a lightweight transactional email API, without marketing pages, automation, or a marketing-facing dashboard, are also a poor fit. Bringing in a full marketing suite for a narrow transactional-email use case adds cost and complexity that a purpose-built transactional email service would avoid.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Email marketing and automation form the foundation: a drag-and-drop email editor with a sizable template library, list segmentation, and a visual workflow builder that triggers automated sequences off events like opens, clicks, purchases, tag changes, or custom API events. Landing pages and the Conversion Funnel tool (previously called Autofunnel) sit alongside this, letting users assemble a landing page, email sequence, sales page, and checkout into a single funnel without leaving the platform.$q$, $q$Webinars are built directly into the platform rather than requiring a separate tool, with attendee limits that scale by plan. An AI-assisted website builder generates a basic site from a short description, complementing the AI email generator, AI subject line suggestions, and an AI campaign generator that can draft a starting campaign from a stated goal.$q$, $q$Beyond the core, GetResponse supports multichannel outreach through SMS, web push notifications, popups, and live chat, along with e-commerce integrations for product recommendations and abandoned cart automation, plus reporting and analytics for tracking campaign and automation performance. Higher tiers add more contacts, additional team seats, and expanded automation and e-commerce capacity, while the top contact-sales tier is aimed at organizations with the largest lists and the most demanding compliance or support requirements.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', $q$experience$q$, $q$The GetResponse Experience$q$, 2, ARRAY[$q$Day-to-day use centers on a dashboard that ties together contacts, campaigns, automation workflows, and landing pages in one place. For straightforward tasks, sending a newsletter, building a landing page from a template, or setting up a basic welcome sequence, the interface is generally quick to pick up, and the template libraries reduce the need to design from scratch.$q$, $q$The automation workflow builder is more capable than it first appears, supporting branching logic, conditions, and multiple trigger types, but that depth means it takes longer to master than the email editor or landing page tool. Users coming from simpler autoresponder tools should expect a real learning curve if they want to build anything beyond a basic drip sequence.$q$, $q$Support is available through live chat and email, with response quality and access to certain support channels varying by plan tier. Overall, the experience reflects a platform that has matured over more than two decades: broad, generally polished, and oriented toward marketers who want one tool to cover most of their needs rather than a narrow specialist for a single task.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('83a31e14-8b81-4e6f-bd44-bf1082ccd21f', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
