INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$GoDaddy Airo AI site generation$q$, $q$Answer a few prompts or link a social profile and Airo drafts pages, copy, imagery, and a logo suggestion automatically.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Section-based drag-and-drop editor$q$, $q$Rearrange, edit, and restyle pre-built page sections without writing code.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Industry-specific templates$q$, $q$Starter layouts tailored to common small-business categories such as services, restaurants, and retail.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Mobile-responsive design$q$, $q$Sites automatically adapt to phone and tablet screens without separate mobile editing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Basic on-page SEO tools$q$, $q$Editable page titles, meta descriptions, and other fundamentals to help pages get indexed.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Online store (Commerce plans)$q$, $q$Product listings, payment processing, inventory tracking, and order management for small catalogs.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Appointment booking$q$, $q$Lets service-based businesses accept bookings directly from their site on eligible plans.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Email marketing integration$q$, $q$Connects to GoDaddy's email marketing tools to send newsletters and promotions to site visitors.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Free SSL and bundled hosting$q$, $q$Every published site includes HTTPS encryption and hosting managed by GoDaddy.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Mobile app management$q$, $q$GoDaddy's mobile app allows owners to check site stats, manage orders, and make quick edits on the go.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$AI-driven setup (GoDaddy Airo) gets a usable site live in minutes$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$No coding or design experience required$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Domain, hosting, SSL, and support are bundled under one GoDaddy account$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Established customer support channels, including phone and chat$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Entry-level plans are relatively affordable for very simple sites$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Less design flexibility and customization than Wix, Squarespace, or Webflow$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$No permanently free plan, only a limited-time trial$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Renewal pricing after the introductory period is typically higher$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$E-commerce features are basic compared to dedicated platforms like Shopify$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Section-based editor makes highly custom, unique layouts difficult to achieve$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Does GoDaddy Website Builder have a free plan?$q$, $q$No, there isn't a permanent free plan. GoDaddy typically offers a free trial period so you can build and preview a site before subscribing to a paid plan.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Can I sell products online with GoDaddy Website Builder?$q$, $q$Yes. The Commerce and Commerce Plus plans add an online store with product listings, payment processing, and basic inventory and order management.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Do I need coding or design skills to use it?$q$, $q$No. It's a no-code tool built around templates and a section-based drag-and-drop editor, with AI (Airo) generating an initial layout and content for you.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$What is GoDaddy Airo?$q$, $q$Airo is GoDaddy's AI website assistant built into the Website Builder. It generates a starter site, including layout, copy, images, and a logo suggestion, based on details you provide or an existing social profile.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Can I use my own domain name?$q$, $q$Yes. You can connect a domain you already own or purchase a new one through GoDaddy during setup, and domain, hosting, and site management stay under one account.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Local service business site$q$, $q$Quickly launch a simple site with contact details, service descriptions, and booking for a local business such as a salon, contractor, or repair shop.$q$, $q$Local service providers and small business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Small online store$q$, $q$Sell a modest product catalog with basic payment processing and inventory tracking using the Commerce plans.$q$, $q$Solo entrepreneurs and small retailers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Professional or portfolio site$q$, $q$Present services, a bio, and contact information for freelancers or consultants who need credibility online without a complex build.$q$, $q$Freelancers and independent consultants$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Restaurant or hospitality site$q$, $q$Publish a menu, location and hours, and booking or reservation information for a restaurant or hospitality business.$q$, $q$Restaurants and small hospitality businesses$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Basic$q$, $q$Introductory pricing starting around $9.99/month (billed annually; varies by promotion and region)$q$, $q$Monthly or annual$q$, $q$["AI-generated starter site via GoDaddy Airo","Mobile-responsive template","Free SSL certificate","Basic on-page SEO fields","Site analytics"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Premium$q$, $q$Higher than Basic; exact current price varies by promotion and region$q$, $q$Monthly or annual$q$, $q$["Everything in Basic","Appointment/booking tools","Email marketing integration","Expanded storage and bandwidth","Additional design customization options"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Commerce$q$, $q$Higher than Premium; exact current price varies by promotion and region$q$, $q$Monthly or annual$q$, $q$["Everything in Premium","Online store with product listings","Built-in payment processing","Inventory and order management","Basic shipping configuration"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$Commerce Plus$q$, $q$Highest tier; exact current price varies by promotion and region$q$, $q$Monthly or annual$q$, $q$["Everything in Commerce","Expanded storage for larger catalogs","Advanced selling and checkout tools","Priority customer support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$GoDaddy Website Builder is the do-it-yourself site-building product from GoDaddy Inc., the Tempe, Arizona-based domain registrar and hosting company founded in 1997 and publicly traded as NYSE: GDDY. It bundles a drag-and-drop editor, a library of industry templates, and GoDaddy Airo, an AI assistant that drafts a working website from a few prompts, letting non-technical users publish a site the same day they sign up.$q$, $q$Rather than starting from a blank canvas, most users begin by describing their business or linking an existing social profile; Airo then generates page layouts, sample copy, a color palette, and imagery that can be edited or replaced. This is positioned as a faster on-ramp than traditional builders such as Wix or Squarespace for people who mainly want a presentable site rather than granular design control.$q$, $q$The product sits inside GoDaddy's broader small-business suite, so it's commonly bought alongside a domain name, business email, and, on higher tiers, an online store. Plans range from a basic informational-site tier up to commerce tiers that add product catalogs, payments, and inventory tools, with pricing and renewal terms set by GoDaddy rather than fixed indefinitely at the introductory rate.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$who-its-for$q$, $q$Who GoDaddy Website Builder Is For$q$, 2, ARRAY[$q$The product targets small business owners, solo entrepreneurs, freelancers, and local service providers -contractors, salons, consultants, restaurants- who need an online presence quickly and don't have a designer or developer on staff. Its AI-first setup and simplified editor are built for people who would otherwise be intimidated by a traditional builder or a CMS like WordPress.$q$, $q$It also suits existing GoDaddy customers who already register domains or buy hosting there and want one vendor and one bill for domain, email, hosting, and site management, plus phone-based support if something goes wrong.$q$, $q$Businesses that need a simple online store running fast -a handful of products, straightforward shipping, one or two payment methods- can reasonably use the Commerce tiers instead of standing up a dedicated e-commerce platform, as long as their catalog and workflow needs stay modest.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Developers, designers, and agencies who need pixel-level control over layout, custom code, or a specific tech stack will find the editor restrictive; GoDaddy Website Builder doesn't offer the open theming, plugin ecosystems, or code-level access found in WordPress, Webflow, or some competing builders.$q$, $q$Merchants with large or complex catalogs, multi-channel inventory, advanced shipping rules, or subscription and marketplace requirements are better served by a dedicated commerce platform such as Shopify or WooCommerce, since GoDaddy's commerce tools are scaled for small, simple stores.$q$, $q$Content-heavy publishers, bloggers who need fine-grained taxonomy and SEO control, and anyone who wants a permanently free tier should also look elsewhere: there is no free-forever plan, only a trial, and renewal pricing after any introductory period is typically higher than the first term's price.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$GoDaddy Airo AI website generation sits at the center of the product: users answer a short set of questions or link a social account, and Airo produces a structured, ready-to-edit site with copy, imagery, and a matching logo suggestion in minutes rather than hours.$q$, $q$Beyond the AI setup, the builder offers industry-specific templates, a drag-and-drop page editor, mobile-responsive output by default, built-in analytics, basic on-page SEO fields such as page titles and meta descriptions, free SSL, and integrations for email marketing and appointment booking on relevant plans.$q$, $q$Commerce-tier plans add an online store with product listings, GoDaddy's own payment processing plus card and PayPal support, inventory tracking, and order management, while GoDaddy's mobile app lets owners manage orders, view site stats, and make quick edits from a phone.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', $q$the-experience$q$, $q$The GoDaddy Website Builder Experience$q$, 2, ARRAY[$q$Onboarding starts with a conversational setup: GoDaddy Airo asks what the business does, who it serves, and where its existing content lives -a Facebook page, Instagram account, or Google Business Profile, for example- then assembles a starter site using that input alongside GoDaddy's template library.$q$, $q$From there, editing happens in a simplified, section-based interface rather than a fully free-form canvas -users pick from suggested layouts, swap images, and adjust text and colors- which keeps the learning curve low but means highly custom designs require more workarounds than in a code-open builder.$q$, $q$Publishing, domain connection, and basic hosting are handled within the same GoDaddy account, and day-to-day support leans on GoDaddy's own customer service channels, chat and phone, rather than a large third-party template marketplace or developer community, a different support model than community-driven builders.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
