INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7d3da374-bd31-46df-a1d1-306837c8aaf8', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Event-Based Data Model$q$, $q$Every interaction, from pageviews to purchases, is captured as a discrete event with parameters, replacing the older session-and-pageview model used by Universal Analytics.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Enhanced Measurement$q$, $q$Automatically tracks common interactions such as scrolls, outbound link clicks, site search, file downloads, and video engagement without any extra tagging.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Explorations$q$, $q$A free-form analysis workspace offering funnel, path, cohort, and segment-overlap exploration for custom analysis beyond the standard prebuilt reports.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$BigQuery Export$q$, $q$Links a property to BigQuery for raw, unsampled event-level data export, enabling custom SQL analysis and long-term data retention beyond GA4's default limits.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Google Ads Integration$q$, $q$Connects conversion data and audiences directly to Google Ads campaigns for attribution reporting, conversion import, and remarketing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Predictive Metrics and AI Insights$q$, $q$Surfaces machine-learning-based metrics such as purchase probability and churn probability when a property has sufficient historical conversion data.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Cross-Platform Measurement$q$, $q$Combines web and mobile app data from the same business into a single GA4 property for a unified view of the customer journey.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Custom Dimensions, Metrics, and Conversions$q$, $q$Lets teams define business-specific events, parameters, and key conversion actions beyond the automatically collected data.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Audience Builder$q$, $q$Builds behavior- and event-based audiences that can be used for remarketing in Google Ads or for segmenting reports.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Realtime and DebugView Reporting$q$, $q$Shows live user activity and individual event streams, which is useful for verifying that tracking and custom events are firing correctly.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Free for the vast majority of websites and apps, with no cost barrier to entry$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Deep native integration with Google Ads and BigQuery for attribution and advanced analysis$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Event-based model captures richer behavioral detail than simple pageview tracking$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Explorations and predictive metrics support advanced analysis without requiring a dedicated data team$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Cross-platform properties unify web and app analytics in a single reporting view$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Steep learning curve for teams coming from Universal Analytics' session-based reports$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Default event and user-level data retention is limited without setting up BigQuery export$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Some European regulators have raised data-transfer concerns affecting adoption in certain markets$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Sampling and data thresholds can still apply in complex explorations on high-traffic properties$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$No dedicated official mobile app for GA4, so on-the-go access relies on a mobile browser$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Is Google Analytics free to use?$q$, $q$Yes. The standard GA4 property is free with generous data limits for most websites and apps. Google Analytics 360 is a paid enterprise tier with higher processing limits, SLAs, and dedicated support, available through custom-priced contracts.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$What happened to Universal Analytics?$q$, $q$Universal Analytics (UA) was the predecessor to GA4. It stopped processing new data in mid-2023 and has since been fully retired, so all properties now run on the GA4 architecture.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Does Google Analytics work for mobile apps as well as websites?$q$, $q$Yes. App measurement is implemented through the Firebase SDK, which uses the same GA4 event model as the web, and a single property can combine both web and app data.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$How is GA4 different from the older version of Google Analytics?$q$, $q$GA4 uses an event-based data model where every interaction is recorded as an event, instead of UA's session-and-pageview structure. This changed report names, default metrics, and how funnels and conversions are configured.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Can I export or query my Google Analytics data directly?$q$, $q$Yes. Linking a property to BigQuery exports raw event-level data (daily on the free tier, with streaming export available on Google Analytics 360) for custom SQL analysis outside the standard reports.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Ecommerce Conversion Tracking$q$, $q$Track the full purchase funnel, from product views and add-to-cart events through checkout steps and completed transactions, to identify drop-off points and measure revenue by channel.$q$, $q$Online retailers and DTC brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Marketing Campaign Attribution$q$, $q$Measure which channels and campaigns drive traffic and conversions, and feed conversion data back into Google Ads for bid optimization and remarketing audiences.$q$, $q$Marketers and growth teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Content and Engagement Analysis$q$, $q$Analyze which pages and content keep visitors engaged, using scroll depth, time on page, and event-based engagement metrics rather than raw pageview counts.$q$, $q$Publishers, bloggers, and content teams$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Mobile App Analytics$q$, $q$Use the Firebase SDK to track in-app events, screen views, and conversions, and combine app data with web data in a single cross-platform property.$q$, $q$App developers and product teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$GA4 Standard$q$, $q$Free$q$, $q$N/A$q$, $q$["Core acquisition, engagement, monetization, and retention reports","Explorations for funnel, path, and cohort analysis","Enhanced measurement and custom event tracking","Daily BigQuery data export","Google Ads integration for attribution and remarketing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$Google Analytics 360$q$, $q$Custom$q$, $q$Annual contract$q$, $q$["Higher data volume and reporting thresholds","SLA-backed processing and support","Streaming BigQuery export","Roll-up reporting across multiple properties","Dedicated account and technical support team"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Google Analytics is Google's web and mobile app analytics platform, now built entirely on the GA4 (Google Analytics 4) architecture. It lets website and app owners track visitor behavior, measure marketing campaign performance, and understand how people move through a digital product, from first visit to purchase or sign-up. The service traces back to Google's 2005 acquisition of Urchin Software, whose tracking technology became the basis for the original Google Analytics.$q$, $q$GA4 represents a significant redesign of the product. It replaced Universal Analytics (UA), the previous version, which stopped processing new hits in mid-2023 and was later fully retired, forcing every organization on the old platform to migrate. Instead of the session-and-pageview model UA used, GA4 records everything, including pageviews, clicks, scrolls, video plays, and purchases, as discrete events, giving analysts a more flexible and granular dataset to query.$q$, $q$The platform integrates natively with other Google products: Google Ads for campaign attribution and audience syncing, BigQuery for raw data export and advanced SQL analysis, Google Tag Manager for deployment, and Looker Studio for custom reporting and dashboards. A free tier covers the vast majority of websites and apps, while Google Analytics 360 is a paid enterprise tier for organizations that need higher data limits, SLAs, and advanced support.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$who-google-analytics-is-for$q$, $q$Who Google Analytics Is For$q$, 2, ARRAY[$q$Google Analytics is aimed at anyone who runs a website, mobile app, or online store and needs to understand where traffic comes from and what visitors do once they arrive. Small business owners and bloggers use it to see which channels drive visits and which pages perform best, without paying for a dedicated analytics tool.$q$, $q$Marketing teams and agencies rely on it to measure campaign ROI, build audiences for remarketing, and connect ad spend in Google Ads directly to on-site conversions. Because it is free at the core tier and widely documented, it is often the default analytics choice for freelancers and small marketing teams managing many client sites.$q$, $q$Ecommerce businesses and product teams get particular value from GA4's event-based model, which is well suited to tracking multi-step funnels, such as product views, add-to-cart actions, checkout steps, and purchases, and to combining web and app data from the same business into a single property. Data analysts who want to go beyond the standard reports can export raw event data to BigQuery for custom modeling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Organizations with strict data-residency or data-sovereignty requirements, particularly in parts of the European Union, should evaluate Google Analytics carefully. Some European data protection authorities have raised concerns about transatlantic data transfers tied to Google's infrastructure, and a few have restricted or discouraged its use for certain public-sector or highly regulated use cases.$q$, $q$Teams that specifically want simple, session-based pageview reporting rather than an event-based model may find GA4's structure harder to adopt at first. The transition from Universal Analytics changed report structures, session definitions, and metric names, and organizations that never fully migrated their custom reports may still be re-learning the reporting interface.$q$, $q$Businesses that need full ownership of raw analytics data with no third-party processing, long retention windows without exporting to BigQuery, or granular server-side control over what is collected may be better served by a self-hosted or privacy-first analytics tool. GA4's standard event-level data retention is limited by default, and longer retention generally requires exporting to BigQuery, an extra step some teams may not want to manage.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$GA4's reporting centers on an event-based data model: every user interaction, from a pageview to a scroll to a purchase, is recorded as an event with parameters, rather than being forced into a fixed pageview and session structure. Enhanced measurement automatically captures common events like outbound clicks, file downloads, and video engagement without extra setup, and custom events and conversions can be defined for anything else that matters to the business.$q$, $q$The Explore section provides free-form analysis tools, including funnel exploration, path exploration, segment overlap, and cohort analysis, that go beyond the standard prebuilt reports and let analysts build custom breakdowns without needing SQL. GA4 also includes AI-driven insights and predictive metrics, such as purchase probability and churn probability, when there is enough historical conversion data in a property.$q$, $q$Integration is a core strength: BigQuery export makes raw, unsampled event data available for advanced analysis, Google Ads integration allows building remarketing audiences and importing conversions for bid optimization, and cross-platform properties let a single GA4 property combine data from a website and its companion mobile app to build a unified view of the user journey.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', $q$the-google-analytics-experience$q$, $q$The Google Analytics Experience$q$, 2, ARRAY[$q$Google Analytics is used entirely through a web-based interface at analytics.google.com; there is no separate desktop application, and setup for a website typically means adding a small tracking snippet or configuring it through Google Tag Manager. For apps, it is implemented via the Firebase SDK, which shares the same underlying GA4 event model.$q$, $q$New users, especially those who managed properties under Universal Analytics, often describe an adjustment period: report names, default metrics, and navigation differ from the old interface, and some previously simple questions now require building a custom exploration. Google provides in-product guidance, a Skillshop training program, and an active help community to shorten that learning curve.$q$, $q$Once configured, the day-to-day experience centers on a handful of standard reports covering acquisition, engagement, monetization, and retention, plus the Explore workspace for anything custom, with Looker Studio commonly used alongside it to build shareable dashboards. For teams that outgrow the free tier's data limits or need guaranteed processing volumes and support SLAs, Google Analytics 360 offers the same interface with higher thresholds and dedicated account support.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
