INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('504c1944-1d50-48a6-8bbd-c32da5230932', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Assignments and classwork$q$, $q$Create assignments, quizzes, and materials with due dates, point values, and topic labels, and let students submit work directly through attached Drive files.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Automatic Drive organization$q$, $q$Every assignment and submission is automatically filed into structured folders in Google Drive for the teacher and each student.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Built-in gradebook$q$, $q$Grades entered on an assignment sync to a class gradebook and can be returned to students automatically once graded.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Class stream and comments$q$, $q$A shared stream for announcements plus comment threads on individual assignments for class-wide or private teacher-student discussion.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Google Meet integration$q$, $q$Start or join video class sessions directly from Classroom, with paid tiers adding breakout rooms, attendance tracking, and live streaming.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Guardian email summaries$q$, $q$Parents and guardians can opt into automated email digests summarizing upcoming and missing work for their student.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Reuse and templates$q$, $q$Teachers can duplicate or reuse past assignments and posts across classes and terms instead of rebuilding classwork from scratch.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Originality reports$q$, $q$Available on paid Workspace for Education tiers, this checks student writing against web sources and a private repository of student submissions.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Practice sets$q$, $q$Interactive assignments that give students instant feedback on certain question types and surface performance insights to teachers.$q$, 8);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Google Classroom API$q$, $q$A public API lets developers and school IT teams integrate rosters, coursework, and grades with other education tools.$q$, 9);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Free to use for the core product, with no cost barrier for individual teachers or schools on Workspace for Education Fundamentals$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Deep integration with Google Docs, Sheets, Slides, Forms, Drive, and Meet reduces app-switching for Google-based schools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Simple, low-clutter interface that is easy for both teachers and students to learn quickly$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Strong mobile apps on iOS and Android that support submitting and reviewing work from a phone$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Automatic file organization in Drive removes manual folder management for teachers and students$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Limited native analytics and reporting compared with dedicated LMS platforms unless a paid Workspace upgrade tier is purchased$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$No built-in support for complex features like degree audits, SCORM/xAPI packages, or certification tracking$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Customization of course layout, branding, and grading schemes is minimal compared with platforms like Canvas or Moodle$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Best experience assumes a Google-centric school; integration with Microsoft 365/Teams environments is weaker$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Advanced features such as originality reports, breakout rooms, and gradebook analytics require paid add-on tiers, not the free plan$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Is Google Classroom free?$q$, $q$Yes, the core Classroom product is free for schools on Google Workspace for Education Fundamentals and for individuals with a personal Google account. Paid Workspace for Education tiers add extra features on top of the same free Classroom base.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Do students need a Google account to use Classroom?$q$, $q$Yes, both teachers and students need a Google account, either a personal account or one provisioned by their school through Workspace for Education.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Can parents or guardians see their child's assignments in Classroom?$q$, $q$Parents don't get direct access to the Classroom interface, but they can opt into automated email summaries that show upcoming and missing work for their student.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Does Google Classroom work without an internet connection?$q$, $q$Some functionality, like viewing previously loaded assignments or drafting work in offline-enabled Docs, can work offline, but most core Classroom features require an internet connection to sync.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$What's the difference between Google Classroom and Google Meet?$q$, $q$Classroom is the assignment and communication hub for a class, while Meet is Google's video conferencing tool. Classroom integrates with Meet so teachers can launch or link video class sessions directly from a course, but they are separate products.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Daily K-12 classroom management$q$, $q$Teachers post assignments, quizzes, and announcements, and track submissions and grades in one place instead of juggling paper handouts and separate grading spreadsheets.$q$, $q$K-12 teachers and students$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Hybrid and remote instruction$q$, $q$Schools use Classroom alongside Google Meet to run live or asynchronous lessons, distribute materials, and keep attendance and participation organized across in-person and remote students.$q$, $q$Schools running hybrid or remote learning programs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Small higher-ed courses and seminars$q$, $q$Instructors teaching smaller university courses or continuing-education seminars use Classroom as a lightweight alternative to a full campus LMS for distributing readings and collecting assignments.$q$, $q$University instructors and adjunct faculty$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Tutoring, homeschooling, and community programs$q$, $q$Independent tutors, homeschool co-ops, and nonprofit or after-school programs use Classroom to organize lessons, share resources, and communicate with students and parents without paying for a dedicated LMS.$q$, $q$Tutors, homeschool educators, and community program leaders$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Education Fundamentals$q$, $q$Free$q$, $q$N/A$q$, $q$["Core Google Classroom","Docs, Sheets, Slides, Forms","Google Meet video calls","Gmail and Drive storage for eligible institutions","Basic admin console for school IT"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Education Standard$q$, $q$Contact sales$q$, $q$Annual, per student$q$, $q$["Everything in Fundamentals","Enhanced security center","Advanced device and endpoint management","Additional data protection controls"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Teaching and Learning Upgrade$q$, $q$Contact sales$q$, $q$Annual, per license$q$, $q$["Add-on to Fundamentals or Standard","Originality reports","Practice sets with instant feedback","Gradebook analytics and insights","Meet breakout rooms, attendance, and live streaming"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$Education Plus$q$, $q$Contact sales$q$, $q$Annual, per student$q$, $q$["Combines Standard security features with Teaching and Learning Upgrade features","Premium support options","Eligibility for additional third-party ed-tech integrations"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Google Classroom is a free learning management tool that Google launched in 2014 to help teachers organize coursework without paperwork. It connects to Google Workspace apps like Docs, Drive, Meet, and Gmail so a teacher can post an assignment, attach a document, set a due date, and grade the submission without leaving a single interface.$q$, $q$The product is built around a simple structure: a class stream for announcements and discussion, a classwork tab for assignments, quizzes, and materials, and a people tab for managing student and co-teacher rosters. Everything a student turns in is automatically organized into a Drive folder, and grades sync to a built-in gradebook.$q$, $q$Classroom is bundled into Google Workspace for Education, which has a free Fundamentals tier used by most K-12 schools and universities, plus paid upgrade tiers (Standard, Teaching and Learning Upgrade, and Education Plus) that add security controls, originality checking, and analytics on top of the same core Classroom experience.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$who-its-for$q$, $q$Who Google Classroom Is For$q$, 2, ARRAY[$q$K-12 teachers and school districts are the primary audience, especially schools already using Chromebooks and Google Workspace for Education. Classroom's tight integration with Docs, Forms, and Meet makes it a natural fit for administering daily assignments, quizzes, and virtual class sessions.$q$, $q$Higher-education instructors running smaller courses, seminars, or supplemental sections also use Classroom for its low setup overhead compared with full campus LMS platforms like Canvas or Moodle. It works well for independent tutors, homeschool co-ops, and nonprofit or after-school programs that need a free way to organize lessons and track student work.$q$, $q$Because it requires only a Google account, it also suits any instructor who wants a lightweight system for a short course, workshop, or training cohort without procurement or IT approval for a dedicated LMS.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Large universities and institutions that need deep integration with student information systems, accreditation reporting, complex degree-audit workflows, or SCORM/xAPI compliant course packages will find Classroom too limited; those needs are typically served by full-scale LMS platforms such as Canvas, Blackboard, or Moodle.$q$, $q$Organizations that are not Google-centric, for example schools standardized on Microsoft 365 and Teams, will face friction since Classroom is built around Google Drive, Docs, and Meet rather than the Microsoft ecosystem.$q$, $q$Corporate training teams needing certifications, compliance tracking, e-commerce for paid courses, or detailed learner analytics across thousands of employees will generally need a dedicated corporate LMS, since Classroom's feature set and reporting are designed around K-12 and higher-ed classroom workflows rather than enterprise training programs.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$Assignments and classwork let teachers distribute documents, quizzes built on Google Forms, and materials with due dates, point values, and topic categories, while students submit work directly through Drive attachments. The built-in gradebook records scores and can return grades to students automatically.$q$, $q$Communication tools include a class stream for announcements, comment threads on individual assignments, private teacher-student comments, and guardian email summaries that give parents a periodic digest of upcoming and missed work. Integration with Google Meet adds video class sessions directly from the Classroom interface.$q$, $q$Paid Workspace for Education upgrade tiers add originality reports for detecting unoriginal student writing, gradebook analytics and insights dashboards, Meet features like breakout rooms, attendance tracking, and live streaming, plus practice sets that auto-generate feedback on certain question types.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', $q$the-experience$q$, $q$The Google Classroom Experience$q$, 2, ARRAY[$q$Day to day, Classroom feels like a simplified extension of Gmail and Drive rather than a standalone platform: the interface is uncluttered, navigation is limited to a handful of tabs, and most actions (attaching a file, assigning to specific students, setting a due date) take only a couple of clicks.$q$, $q$The mobile apps for iOS and Android mirror the web experience closely enough that students can review classwork, submit files, and get notifications from a phone, which matters for classrooms without one-to-one laptop access.$q$, $q$The tradeoff for that simplicity is limited customization: there is no visual course builder, no native certificates, and no built-in analytics beyond the paid tiers, so teachers who want deeper reporting or a highly branded course experience will feel the platform's ceiling fairly quickly.$q$]::text[], 4);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', 'd5f794d8-1509-49c9-ac15-6834dce260e9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', '5e4d4807-cae2-410c-9e7a-df0798a917cb') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('569c81e4-5756-4a43-b262-297772fa2a0c', '7336153f-a26b-491c-b927-faf4f5a8d103') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Compute Engine$q$, $q$Configurable virtual machines with a wide range of machine types, custom CPU/memory sizing, and per-second billing for general-purpose workloads.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Google Kubernetes Engine (GKE)$q$, $q$A managed Kubernetes service for deploying, scaling, and operating containerized applications, built by the originators of the Kubernetes project.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Cloud Storage$q$, $q$Durable, globally available object storage with multiple storage classes for hot, infrequently accessed, and archival data.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$BigQuery$q$, $q$A serverless, highly scalable SQL data warehouse for running analytical queries over large datasets without provisioning infrastructure.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Vertex AI$q$, $q$A unified machine learning platform covering model training, foundation model access, tuning, and deployment for AI-driven applications.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Cloud Run and Cloud Functions$q$, $q$Serverless compute options for running containers or event-driven functions without managing the underlying servers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Cloud SQL and Spanner$q$, $q$Managed relational database services covering traditional MySQL/PostgreSQL/SQL Server workloads and globally distributed, horizontally scalable databases.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$VPC Networking and Cloud Load Balancing$q$, $q$Software-defined networking, global load balancing, and connectivity options for building secure, high-performance network architectures.$q$, 7);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$IAM and Security Command Center$q$, $q$Fine-grained identity and access management alongside centralized security and risk visibility across cloud resources.$q$, 8);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Always Free tier plus free trial credit lowers the barrier to trying real production-grade services$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Strong data analytics (BigQuery) and machine learning tooling (Vertex AI) for data-driven teams$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Global network infrastructure with strong performance, reliability, and low-latency connectivity$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Deep container and Kubernetes support from the team that created and open-sourced Kubernetes$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Granular, usage-based pricing lets costs scale directly with actual consumption$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Steep learning curve for teams without prior cloud or infrastructure experience$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Usage-based billing can produce unpredictable costs without careful monitoring and budget alerts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Smaller market share than AWS means a somewhat smaller pool of third-party tools and community tutorials$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Some services and regions have less global coverage compared to the largest competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Best enterprise pricing (committed-use discounts, dedicated support) typically requires direct engagement with sales$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$What is Google Cloud used for?$q$, $q$Google Cloud is used for hosting websites and applications, storing data, running analytics workloads, building and deploying machine learning models, and operating containerized infrastructure, among many other computing and data needs.$q$, 0);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Is Google Cloud free?$q$, $q$Google Cloud offers an Always Free tier with limited monthly usage of select services indefinitely, plus a free trial that provides introductory credit for new accounts for a limited time. Usage beyond these limits is billed under standard pay-as-you-go pricing.$q$, 1);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$How is Google Cloud priced?$q$, $q$Most Google Cloud services are billed on a usage basis, meaning customers pay for the compute, storage, and data processed rather than a fixed subscription fee. Discounts are available for sustained or committed usage, particularly for enterprise customers.$q$, 2);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$What is the difference between Google Cloud and Google Workspace?$q$, $q$Google Cloud Platform provides infrastructure and developer services such as compute, storage, databases, and AI, while Google Workspace is a separate suite of productivity and collaboration apps like Gmail, Docs, and Drive. Both are part of Google's broader cloud offerings but serve different purposes.$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Does Google Cloud support Kubernetes?$q$, $q$Yes. Google Kubernetes Engine (GKE) is a managed Kubernetes service on Google Cloud, and Google is the company that originally created and open-sourced the Kubernetes project.$q$, 4);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Web and mobile app hosting$q$, $q$Teams deploy backend services and APIs on Compute Engine, GKE, or Cloud Run, using managed load balancing and databases to support production traffic.$q$, $q$Startups and application development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Data warehousing and analytics$q$, $q$Organizations centralize large datasets in BigQuery to run SQL-based analytics and reporting without managing dedicated data warehouse infrastructure.$q$, $q$Data engineers and business intelligence teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Machine learning and AI development$q$, $q$Data science teams use Vertex AI to train custom models, access foundation models, and manage the full machine learning lifecycle from experimentation to deployment.$q$, $q$ML engineers and data scientists$q$, 2);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Enterprise workload migration$q$, $q$Enterprises migrate on-premises applications and databases to Google Cloud's managed infrastructure to reduce hardware management and modernize legacy systems.$q$, $q$Enterprise IT and operations teams$q$, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Always Free$q$, $q$$0$q$, $q$Ongoing (monthly limits)$q$, $q$["Limited free usage of select services such as Compute Engine, Cloud Storage, and BigQuery","No time limit as long as usage stays within monthly free limits","Access to core services for learning and small-scale projects"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Free Trial$q$, $q$$0 (introductory credit)$q$, $q$One-time, limited period$q$, $q$["Introductory credit applied to eligible services","Access to most Google Cloud products during the trial period","Automatic transition to pay-as-you-go pricing after the trial ends or credit is used"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Pay-As-You-Go$q$, $q$Usage-based$q$, $q$Monthly$q$, $q$["Billing based on actual compute, storage, and data processing consumed","No upfront commitment required","Budgets and billing alerts to monitor and control spend"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, features, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$Enterprise / Committed Use$q$, $q$Custom pricing$q$, $q$Annual or custom contract$q$, $q$["Discounted rates for committed usage levels","Dedicated technical account management","Custom support agreements and negotiated terms via Google Cloud sales"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Google Cloud Platform (GCP) is Google's public cloud computing platform, offering infrastructure-as-a-service, platform-as-a-service, and serverless computing environments accessible at cloud.google.com. It runs on the same global infrastructure that powers Google Search, YouTube, and Gmail, giving customers access to compute, storage, networking, databases, and machine learning services across regions worldwide.$q$, $q$Originally launched in 2008 with App Engine, GCP has grown into one of the major hyperscale cloud providers alongside AWS and Microsoft Azure. Its portfolio spans core infrastructure (Compute Engine, Cloud Storage, VPC networking), managed Kubernetes (GKE), fully managed databases (Cloud SQL, Spanner, Firestore, BigQuery), and an increasingly prominent AI and data analytics stack anchored by Vertex AI and BigQuery ML.$q$, $q$GCP is organized around a pay-as-you-go usage model layered with an Always Free tier and free trial credit for new accounts, letting individual developers, startups, and large enterprises use the same underlying services at different scales. The platform is managed through a web-based console, a command-line SDK (gcloud), REST and gRPC APIs, and infrastructure-as-code tools such as Terraform and Deployment Manager.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$who-google-cloud-is-for$q$, $q$Who Google Cloud Is For$q$, 2, ARRAY[$q$Google Cloud is built for organizations that need to run production workloads on managed infrastructure rather than owning physical servers. Software engineering teams building web and mobile backends, data engineers processing large datasets, and DevOps teams running containerized applications are core users, since GCP's compute and Kubernetes tooling are designed for exactly those workflows.$q$, $q$Data-heavy organizations are a particularly strong fit. BigQuery's serverless data warehouse and the broader analytics stack, including Dataflow, Dataproc, and Looker, attract companies doing large-scale reporting, business intelligence, and data science work that would be expensive or slow to run on self-managed hardware.$q$, $q$Enterprises already invested in Google Workspace, Android, or machine learning research also gravitate toward GCP because of integration points and Google's applied AI research heritage, which surfaces in products like Vertex AI. Startups benefit from free-tier credits and pay-as-you-go pricing that lets them scale spend with growth rather than provisioning capacity in advance.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$who-should-avoid-it$q$, $q$Who Should Avoid It$q$, 2, ARRAY[$q$Individuals or small teams with no cloud or infrastructure experience may find GCP's console overwhelming, since it exposes dozens of interconnected services, including IAM, networking, billing projects, and quotas, that require some systems knowledge to configure correctly and avoid unexpected costs.$q$, $q$Organizations already heavily invested in AWS or Azure tooling, certifications, and internal expertise may not see enough differentiation to justify a migration, given the operational cost of retraining staff and re-architecting workloads for a different provider's APIs and conventions.$q$, $q$Businesses that need simple, fixed-cost hosting for a small website or app may be better served by simpler platforms, such as managed app hosts or traditional web hosting, rather than a full hyperscale cloud, since GCP's granular usage-based billing and service breadth add complexity that isn't necessary for small, low-traffic projects.$q$]::text[], 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$main-features$q$, $q$Main Features$q$, 2, ARRAY[$q$At its core, GCP provides configurable virtual machines (Compute Engine), managed Kubernetes clusters (Google Kubernetes Engine), and serverless compute options (Cloud Run, Cloud Functions) so teams can choose how much infrastructure they want to manage directly. Cloud Storage, Persistent Disk, and Filestore cover object, block, and file storage needs, backed by a global network of regions and edge points of presence.$q$, $q$On the data side, BigQuery offers a serverless, SQL-based data warehouse capable of querying large datasets without managing servers, while Cloud SQL, Spanner, Firestore, and Bigtable cover relational and NoSQL database needs at different scales. Vertex AI unifies Google's machine learning tooling, including access to foundation models, custom model training, and MLOps pipelines, for teams building AI-driven features.$q$, $q$Supporting these workloads are identity and access management (IAM), Virtual Private Cloud networking, Cloud Load Balancing, and security services like Security Command Center, alongside developer tooling such as Cloud Build, Artifact Registry, and Terraform-based infrastructure automation for teams practicing infrastructure as code.$q$]::text[], 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('d05ce7d8-d828-41bd-aa04-c81764640a9f', $q$the-google-cloud-experience$q$, $q$The Google Cloud Experience$q$, 2, ARRAY[$q$Day-to-day interaction with Google Cloud happens mostly through the Cloud Console, a web dashboard that surfaces billing, resource monitoring, IAM, and per-service configuration screens, complemented by the gcloud CLI and client libraries for Python, Go, Java, Node.js, and other languages for teams that prefer to manage resources programmatically.$q$, $q$New users start with a free trial that provides introductory credit for a limited time, plus an Always Free tier covering a defined amount of usage on select services indefinitely, which lets developers experiment before committing to paid usage. Billing is organized around projects, with budgets, alerts, and detailed cost breakdowns available to track spend as usage grows.$q$, $q$Support ranges from community forums and documentation for free-tier users to paid support plans with guaranteed response times for production accounts, and enterprises can work with Google Cloud sales for custom pricing, committed-use discounts, and dedicated technical account management as usage scales.$q$]::text[], 4);
